if doc.distribute_charges_based_on == "Amount" and doc.custom_distribute_by_container_qty==1:
    purchase_receipt_invoice = doc.purchase_receipts
    total_container_value = 0
    item_cache = {}

    # Calculate total container value across all items
    # Step 1: Ensure every PR item has a container value
    for pr in purchase_receipt_invoice:
        receipt_type = pr.receipt_document_type
        receipt_name = pr.receipt_document
        receipt_doc = frappe.get_doc(receipt_type, receipt_name)
        # total_quantity=receipt_doc.total_qty

        for item in receipt_doc.items:
            # total_container_value =total_container_value + item.custom_containers
            pr_container_value = item.custom_containers or 0

            if pr_container_value == 0:
                item_doc = item_cache.get(item.item_code) or frappe.get_doc("Item", item.item_code)
                item_cache[item.item_code] = item_doc

                # Find container UOM conversion
                container_factor = None
                for row in item_doc.uoms:
                    if row.uom == "Container":
                        container_factor = row.conversion_factor
                        break

                if container_factor and container_factor > 0:
                    print(f"Item Code: {item.item_code}, Qty: {item.qty}, Stock Qty: {item.stock_qty}")
                    pr_container_value = item.stock_qty / container_factor
                    frappe.db.set_value(f"{receipt_type} Item", item.name, "custom_containers", pr_container_value, update_modified=False)

            total_container_value = total_container_value + pr_container_value

    # Guard against zero denominator
    if not total_container_value:
        frappe.throw("Total container value is zero. Please ensure container data is set or valid UOM conversions exist.")

    # Apply applicable charges to items in the Landed Cost Voucher
    # Step 2: Distribute charges
    for lc_item in doc.items:
        lc_item_code = lc_item.item_code
        lc_item_qty = lc_item.qty  # Get the quantity of the lc_item

        for pr in purchase_receipt_invoice:
            receipt_type = pr.receipt_document_type
            receipt_name = pr.receipt_document
            receipt_doc = frappe.get_doc(receipt_type, receipt_name)

            for pr_item in receipt_doc.items:
                if pr_item.item_code == lc_item_code and pr_item.qty == lc_item_qty:
                    pr_container_value = pr_item.custom_containers or 0

                    if pr_container_value > 0:
                        # Calculate applicable charges based on item quantity and container ratio
                        item_container_ratio = pr_container_value / total_container_value
                        lc_item.applicable_charges = item_container_ratio * doc.total_taxes_and_charges
                        break  
                    # Break the loop once the matching item is found and charges are applied

