try:
    # Retrieve the form data
    sales_doc = frappe.form_dict.get("sales_doc")
    arrival_date = frappe.form_dict.get("arrival_date")

    if not sales_doc or not arrival_date:
        frappe.throw("Sales document ID and arrival date are required")

    # Fetch the Sales Invoice document
    doc = frappe.get_doc("Sales Invoice", sales_doc)

    if not doc:
        frappe.throw(f"No Sales Invoice with ID: {sales_doc} found")

    # Check if the custom fields exist
    try:
        custom_transit_no = doc.custom_transit_no

        # Check if custom_actual_arrival_date is already set
