            doc.custom_actual_arrival_date = arrival_date
        else:
            frappe.throw("Actual arrival date has already been set and cannot be updated")

        doc.custom_shipping_status = "Completed"
        doc.save()
    except AttributeError:
        frappe.throw("Custom fields not found in Sales Invoice")

    # Find all other Sales Invoices with the same custom_transit_no
    invoices = frappe.get_all("Sales Invoice", filters={"custom_transit_no": custom_transit_no, "name": ["!=", sales_doc]})

    for invoice in invoices:
        other_sales_doc = frappe.get_doc("Sales Invoice", invoice.name)

        try:
            other_sales_doc.custom_shipping_status = "Completed"
            other_sales_doc.save()
        except AttributeError:
            frappe.log_error(f"Custom shipping status field not found in Sales Invoice {invoice.name}")

    # Find and update all Purchase Invoices with the same custom_transit_no
